import { useState, useEffect, useCallback, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api, apiPost } from '../utils/api';
import { useToast } from '../components/ui/Toast';
import { motion } from 'framer-motion';
import usePlatformFeatures from '../hooks/usePlatformFeatures';
import styles from './TournamentDetailPage.module.css';

const RANK_COLORS = { 1: '#D29922', 2: '#8B949E', 3: '#CD7F32' };

function Countdown({ endDate }) {
  const [timeLeft, setTimeLeft] = useState('');
  useEffect(() => {
    const calc = () => {
      const diff = new Date(endDate) - new Date();
      if (diff <= 0) return setTimeLeft('Ended');
      const d = Math.floor(diff / 86400000);
      const h = Math.floor((diff % 86400000) / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      setTimeLeft(`${d}d ${h}h ${m}m ${s}s`);
    };
    calc();
    const i = setInterval(calc, 1000);
    return () => clearInterval(i);
  }, [endDate]);
  return <div className={styles.countdownBig}>{timeLeft}</div>;
}

export default function TournamentDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const toast = useToast();
  const [tournament, setTournament] = useState(null);
  const [leaderboard, setLeaderboard] = useState([]);
  const [myEntry, setMyEntry] = useState(null);
  const [strategies, setStrategies] = useState([]);
  const [selectedStrategy, setSelectedStrategy] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [loading, setLoading] = useState(true);
  const { tier: userTier } = usePlatformFeatures();

  const load = useCallback(async () => {
    try {
      const [t, lb, me, strats] = await Promise.all([
        api(`/tournaments/${id}`),
        api(`/tournaments/${id}/leaderboard`).catch(() => ({ results: [] })),
        api(`/tournaments/${id}/my-entry`).catch(() => null),
        api('/strategies').catch(() => []),
      ]);
      setTournament(t);
      setLeaderboard(lb?.results || lb?.leaderboard || []);
      setMyEntry(me);
      setStrategies(Array.isArray(strats) ? strats : strats?.strategies || []);
    } catch { /* handled */ }
    setLoading(false);
  }, [id]);

  useEffect(() => { load(); }, [load]);

  // Poll leaderboard during running state
  useEffect(() => {
    if (!tournament || tournament.status !== 'running') return;
    const i = setInterval(async () => {
      try {
        const lb = await api(`/tournaments/${id}/leaderboard`);
        setLeaderboard(lb?.results || lb?.leaderboard || []);
      } catch {}
    }, 30000);
    return () => clearInterval(i);
  }, [tournament, id]);

  const handleSubmit = async () => {
    if (!selectedStrategy) return toast.warning('Select a strategy', '');
    setSubmitting(true);
    try {
      await apiPost(`/tournaments/${id}/submit`, {
        strategy_name: selectedStrategy,
        strategy_definition: { name: selectedStrategy },
      });
      toast.success('Entry Submitted', `Strategy "${selectedStrategy}" entered!`);
      load();
    } catch (e) {
      toast.error('Submission Failed', e?.message || 'Try again');
    }
    setSubmitting(false);
  };

  if (loading) return <div className={styles.page}><div className={styles.skeleton} /></div>;
  if (!tournament) return <div className={styles.page}><p style={{ color: '#8B949E' }}>Tournament not found.</p></div>;

  const isOpen = tournament.status === 'open';
  const hasEntered = !!myEntry;

  return (
    <div className={styles.page}>
      <button className={styles.backBtn} onClick={() => navigate('/tournaments')}>Back to Tournaments</button>

      <div className={styles.heroSection}>
        <h1 className={styles.title}>{tournament.name}</h1>
        <p className={styles.description}>{tournament.description}</p>
        {isOpen && tournament.end_date && <Countdown endDate={tournament.end_date} />}
        <div className={styles.metaRow}>
          <span>{tournament.start_date?.split('T')[0]} - {tournament.end_date?.split('T')[0]}</span>
          <span>Universe: {tournament.universe || 'us, crypto'}</span>
          <span className={styles.statusTag} style={{ color: { open: '#3FB950', running: '#58A6FF', scored: '#D29922', completed: '#BC8CFF' }[tournament.status] }}>
            {tournament.status?.toUpperCase()}
          </span>
        </div>
      </div>

      {/* Prizes */}
      <div className={styles.prizeSection}>
        <h3>Prizes</h3>
        <div className={styles.prizeCards}>
          {[
            { place: '1st', share: '5%', color: '#D29922', label: 'Gold', extras: 'Featured marketplace + gold badge' },
            { place: '2nd', share: '3%', color: '#8B949E', label: 'Silver', extras: 'Promoted marketplace + silver badge' },
            { place: '3rd', share: '1%', color: '#CD7F32', label: 'Bronze', extras: 'Highlighted marketplace + bronze badge' },
          ].map(p => (
            <div key={p.place} className={styles.prizeCard} style={{ borderColor: p.color + '44' }}>
              <div className={styles.prizePlace} style={{ color: p.color }}>{p.place}</div>
              <div className={styles.prizeShare}>{p.share} Revenue Share</div>
              <div className={styles.prizeExtras}>{p.extras}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Scoring */}
      <div className={styles.scoringBox}>
        <span>60% Sharpe</span><span>25% Consistency</span><span>15% Max Drawdown</span><span>Min 30 trades</span>
      </div>

      {/* Entry Form — tier-gated for free users */}
      {isOpen && !hasEntered && (
        (userTier === 'explorer' || userTier === 'free') ? (
          <div style={{ background: '#161B22', border: '1px solid #D29922', borderRadius: 12, padding: 20, marginBottom: 24, textAlign: 'center' }}>
            <h3 style={{ color: '#D29922', margin: '0 0 8px' }}>Tournament Entry Requires a Subscription</h3>
            <p style={{ color: '#8B949E', fontSize: 14, margin: '0 0 16px' }}>Upgrade to enter tournaments and compete for revenue share prizes.</p>
            <button onClick={() => navigate('/billing')} style={{ padding: '10px 24px', background: '#D29922', border: 'none', borderRadius: 8, color: '#0D1117', fontWeight: 700, cursor: 'pointer' }}>
              Upgrade to Enter
            </button>
          </div>
        ) : (
          <motion.div className={styles.entrySection} initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
            <h3>Submit Your Strategy</h3>
            <div className={styles.entryForm}>
              <select
                className={styles.strategySelect}
                value={selectedStrategy}
                onChange={e => setSelectedStrategy(e.target.value)}
              >
                <option value="">Choose a strategy...</option>
                {strategies.map(s => (
                  <option key={s.name || s.strategy_name || s} value={s.name || s.strategy_name || s}>
                    {s.name || s.strategy_name || s}
                  </option>
                ))}
              </select>
              <button className={styles.submitBtn} onClick={handleSubmit} disabled={submitting}>
                {submitting ? 'Submitting...' : 'Submit Entry'}
              </button>
            </div>
          </motion.div>
        )
      )}

      {hasEntered && (
        <div className={styles.enteredBanner}>
          You've entered with: <strong>{myEntry?.strategy_name || 'Your strategy'}</strong>
        </div>
      )}

      {/* Leaderboard */}
      <div className={styles.leaderboardSection}>
        <h3>Leaderboard {tournament.status === 'running' && <span className={styles.liveTag}>LIVE</span>}</h3>
        {leaderboard.length === 0 ? (
          <p className={styles.emptyLb}>
            {isOpen ? 'Results will appear after the tournament runs.' : 'No entries yet.'}
          </p>
        ) : (
          <div className={styles.lbTable}>
            <div className={styles.lbHeader}>
              <span className={styles.lbRank}>#</span>
              <span className={styles.lbStrategy}>Strategy</span>
              <span className={styles.lbMetric}>Sharpe</span>
              <span className={styles.lbMetric}>Consistency</span>
              <span className={styles.lbMetric}>Max DD</span>
              <span className={styles.lbMetric}>Score</span>
            </div>
            {leaderboard.map((entry, i) => (
              <motion.div
                key={entry.user_id || i}
                className={styles.lbRow}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: i * 0.03 }}
              >
                <span className={styles.lbRank} style={{ color: RANK_COLORS[entry.rank || i + 1] || '#E6EDF3' }}>
                  {entry.rank || i + 1}
                </span>
                <span className={styles.lbStrategy}>{entry.strategy_name || 'Unknown'}</span>
                <span className={styles.lbMetric} style={{ color: (entry.sharpe || 0) > 0 ? '#3FB950' : '#F85149' }}>
                  {(entry.sharpe || 0).toFixed(2)}
                </span>
                <span className={styles.lbMetric}>{((entry.consistency || 0) * 100).toFixed(0)}%</span>
                <span className={styles.lbMetric} style={{ color: '#F85149' }}>
                  {((entry.max_drawdown || 0) * 100).toFixed(1)}%
                </span>
                <span className={styles.lbMetric} style={{ fontWeight: 700, color: '#E6EDF3' }}>
                  {(entry.total_score || 0).toFixed(3)}
                </span>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
